// NewListRequestsPayload builds a policyaccess service listRequests endpoint
// payload.
func NewListRequestsPayload(status *string, apikeyToken *string, sessionToken *string) *policyaccess.ListRequestsPayload {
	v := &policyaccess.ListRequestsPayload{}
	v.Status = status
	v.ApikeyToken = apikeyToken
	v.SessionToken = sessionToken

	return v
}

// NewDecideRequestPayload builds a policyaccess service decideRequest endpoint
// payload.
func NewDecideRequestPayload(body *DecideRequestRequestBody, apikeyToken *string, sessionToken *string) *policyaccess.DecideRequestPayload {
	v := &policyaccess.DecideRequestPayload{
		ID:        *body.ID,
		Status:    *body.Status,
		GrantType: body.GrantType,
	}
	if body.RoleSlugs != nil {
		v.RoleSlugs = make([]string, len(body.RoleSlugs))
		for i, val := range body.RoleSlugs {
			v.RoleSlugs[i] = val
		}
	}
	v.ApikeyToken = apikeyToken
	v.SessionToken = sessionToken

	return v
}

// NewListBypassesPayload builds a policyaccess service listBypasses endpoint
// payload.
func NewListBypassesPayload(apikeyToken *string, sessionToken *string) *policyaccess.ListBypassesPayload {
	v := &policyaccess.ListBypassesPayload{}
	v.ApikeyToken = apikeyToken
	v.SessionToken = sessionToken

	return v
}

// NewRevokeBypassPayload builds a policyaccess service revokeBypass endpoint
// payload.
func NewRevokeBypassPayload(body *RevokeBypassRequestBody, apikeyToken *string, sessionToken *string) *policyaccess.RevokeBypassPayload {
	v := &policyaccess.RevokeBypassPayload{
		GrantID: *body.GrantID,
	}
	v.ApikeyToken = apikeyToken
	v.SessionToken = sessionToken

	return v
}

// ValidateDecideRequestRequestBody runs the validations defined on
// DecideRequestRequestBody
func ValidateDecideRequestRequestBody(body *DecideRequestRequestBody) (err error) {
	if body.ID == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("id", "body"))
	}
	if body.Status == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("status", "body"))
	}
	if body.ID != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.id", *body.ID, goa.FormatUUID))
	}
	if body.Status != nil {
		if !(*body.Status == "approved" || *body.Status == "denied") {
			err = goa.MergeErrors(err, goa.InvalidEnumValueError("body.status", *body.Status, []any{"approved", "denied"}))
		}
	}
	if body.GrantType != nil {
		if !(*body.GrantType == "requester" || *body.GrantType == "requester_roles" || *body.GrantType == "roles") {
			err = goa.MergeErrors(err, goa.InvalidEnumValueError("body.grant_type", *body.GrantType, []any{"requester", "requester_roles", "roles"}))
		}
	}
	return
}

// ValidateRevokeBypassRequestBody runs the validations defined on
// RevokeBypassRequestBody
func ValidateRevokeBypassRequestBody(body *RevokeBypassRequestBody) (err error) {
	if body.GrantID == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("grant_id", "body"))
	}
	if body.GrantID != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.grant_id", *body.GrantID, goa.FormatUUID))
	}
	return
}
